// make-src.cjs — writes the Staff Arts web source tree into ./src.
// Run: node make-src.cjs  (then node make-locales.cjs for locales)
// If you hit "require is not defined": re-run this + delete .next.
const fs = require("fs");
const path = require("path");
const FILES = {
  "src/api/artwork.js": "",
  "src/api/auth.js": "",
  "src/api/client.js": "",
  "src/api/event.js": "",
  "src/api/messages.js": "",
  "src/api/user.js": "",
  "src/app/artwork/[id]/page.js": "",
  "src/app/artwork/new/page.js": "",
  "src/app/events/[id]/page.js": "",
  "src/app/events/page.js": "",
  "src/app/explore/page.js": "",
  "src/app/gallery/page.js": "",
  "src/app/globals.css": "",
  "src/app/layout.js": "",
  "src/app/login/page.js": "",
  "src/app/messages/page.js": "",
  "src/app/page.js": "",
  "src/app/register/page.js": "",
  "src/app/reset-pin/page.js": "",
  "src/app/users/[id]/page.js": "",
  "src/components/ArtworkCard.jsx": "",
  "src/components/ArtworkExploreCard.jsx": "",
  "src/components/ArtworkFeedCard.jsx": "",
  "src/components/EventsStrip.jsx": "",
  "src/components/ExploreCard.jsx": "",
  "src/components/MessageArtworkPreview.jsx": "",
  "src/components/NavBar.jsx": "",
  "src/components/ProfileView.jsx": "",
  "src/components/Providers.jsx": "",
  "src/i18n/index.jsx": "",
  "src/lib/ThemeProvider.jsx": "",
  "src/lib/config.js": "",
  "src/lib/queryClient.jsx": "",
  "src/lib/socket.js": "",
  "src/lib/socketEvents.js": "",
  "src/lib/tokenStorage.js": "",
  "src/lib/uploadArtworkImage.js": "",
  "src/lib/uploadAvatar.js": "",
  "src/lib/uploadEventImage.js": "",
  "src/store/authStore.js": "",
};
let count = 0;
for (const [rel, b64] of Object.entries(FILES)) {
  const full = path.join(__dirname, rel);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, Buffer.from(b64, "base64").toString("utf8"), "utf8");
  count++; console.log("wrote " + rel);
}
console.log("\nDone. " + count + " source files written.");
